SELECT style_name
FROM shoe_styles
WHERE is_active = 1;

SELECT COUNT(DISTINCT size_id) AS total_sizes
  FROM shoe_sizes
 WHERE gender = 'Male';

SELECT DISTINCT region
FROM sales
WHERE size_id = 1;

SELECT SUM(quantity_sold) as total_units_sold
FROM sales
WHERE region = 'North America';

SELECT total_sold, total_inventory
FROM size_reports
WHERE report_id = 1;
